        if regex is not None:
            try:
                return regex.compile(value)
            except regex.error:
                # If it still fails with regex, raise the original re error
                raise argparse.ArgumentTypeError(
                    f"Error in provided regular expression: {value} beginning at index {e.pos}: {e.msg}"
                ) from e
        else:
            # If regex library is not available, provide a helpful error message
            if r"\p{" in value:
                raise argparse.ArgumentTypeError(
                    f"Error in provided regular expression: {value} beginning at index {e.pos}: {e.msg}. "
                    f"You appear to be using Unicode property escapes (\\p{{...}}), "
                    f"which are not supported by Python's 're' module. "
                    f"Install the 'regex' module to use Unicode property escapes: pip install regex"
